sql:
SELECT COUNT(transaction_id) AS transaction_count
FROM transactions
WHERE ticker = 'AAPL';

SELECT market_center_name, location
FROM market_centers
WHERE market_center_id = 0;

SELECT DISTINCT t.company_name
FROM tickers t
INNER JOIN transactions tr ON t.ticker = tr.ticker;

SELECT SUM(commission) AS total_commission
FROM transactions
WHERE broker_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT last_trade_price
FROM tickers
WHERE ticker = 'AAPL';

external_knowledge:
- "Top-performing brokers" are brokers whose total transaction value exceeds the average transaction value; 
- "Specific market center" refers to the market center with a `market_center_id` of 1;
- "Trading volume" is a metaphor for the total transaction value, calculated as the sum of the product of price and quantity for each transaction.
